88	const ircConfigAdapter = createScopedChannelConfigAdapter<
89	  ResolvedIrcAccount,
90	  ResolvedIrcAccount,
91	  CoreConfig
92	>({
93	  sectionKey: "irc",
94	  listAccountIds: listIrcAccountIds,
95	  resolveAccount: adaptScopedAccountAccessor(resolveIrcAccount),
96	  defaultAccountId: resolveDefaultIrcAccountId,
97	  clearBaseFields: [
98	    "name",
99	    "host",
100	    "port",
101	    "tls",
102	    "nick",
103	    "username",
104	    "realname",
105	    "password",
106	    "passwordFile",
107	    "channels",
108	  ],
109	  resolveAllowFrom: (account: ResolvedIrcAccount) => account.config.allowFrom,
110	  formatAllowFrom: (allowFrom) =>
111	    formatNormalizedAllowFromEntries({
112	      allowFrom,
113	      normalizeEntry: normalizeIrcAllowEntry,
114	    }),
115	  resolveDefaultTo: (account: ResolvedIrcAccount) => account.config.defaultTo,
116	});
117	
118	const resolveIrcDmPolicy = createScopedDmSecurityResolver<ResolvedIrcAccount>({
119	  channelKey: "irc",
120	  resolvePolicy: (account) => account.config.dmPolicy,
121	  resolveAllowFrom: (account) => account.config.allowFrom,
122	  policyPathSuffix: "dmPolicy",
123	  normalizeEntry: (raw) => normalizeIrcAllowEntry(raw),
124	});
