// PulseBoard target normalization.
//
// Board targets use "!" as the sigil (e.g. "!general", "!dev").
// Direct-message targets are plain lowercase usernames.
//
// Accepted prefix forms that are stripped before normalization:
//   pulseboard:   pb:   board:   user:

const BOARD_TARGET_RE = /^![a-z0-9_-]+$/u;
const USER_TARGET_RE = /^[a-z0-9_.-]+$/u;

/** Returns true when the normalized target is a board (starts with "!"). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("!");
}

/**
 * Normalize a raw PulseBoard messaging target.
 *
 * Returns the normalized string (e.g. "!general" or "alice") or undefined
 * when the input cannot be resolved to a valid target.
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  let target = raw.trim();
  if (!target) {
    return undefined;
  }

  // Strip well-known prefixes.
  const lower = target.toLowerCase();
  if (lower.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  } else if (lower.startsWith("pb:")) {
    target = target.slice("pb:".length).trim();
  }

  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    // Ensure the board sigil is present.
    if (!target.startsWith("!")) {
      target = `!${target}`;
    }
  } else if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target) {
    return undefined;
  }

  const normalized = target.toLowerCase();
  if (isBoardTarget(normalized)) {
    return BOARD_TARGET_RE.test(normalized) ? normalized : undefined;
  }
  return USER_TARGET_RE.test(normalized) ? normalized : undefined;
}

/** Returns true when raw looks like a valid PulseBoard target id. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  return normalizePulseBoardMessagingTarget(raw) !== undefined;
}

/**
 * Normalize a raw allow-list entry (username or "*").
 * Returns the lowercased username, "*", or empty string for invalid input.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value === "*") {
    return "*";
  }
  // Strip optional prefixes.
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  } else if (value.startsWith("pb:")) {
    value = value.slice("pb:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

export function normalizePulseBoardAllowlist(
  entries?: Array<string | number>,
): string[] {
  return (entries ?? [])
    .map((entry) => normalizePulseBoardAllowEntry(String(entry)))
    .filter(Boolean);
}

export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  senderUsername: string;
}): { allowed: boolean; source?: string } {
  const normalized = new Set(
    params.allowFrom.map((e) => e.trim().toLowerCase()).filter(Boolean),
  );
  if (normalized.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const sender = params.senderUsername.trim().toLowerCase();
  if (sender && normalized.has(sender)) {
    return { allowed: true, source: sender };
  }
  return { allowed: false };
}

