import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

/**
 * Probe the PulseBoard server by attempting a lightweight authenticated
 * GET request to the server's health/me endpoint.
 */
export async function probePulseBoard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseBoardProbe = {
    ok: false,
    serverUrl: account.serverUrl,
    username: account.username,
  };

  if (!account.configured) {
    return { ...base, error: "missing serverUrl or username" };
  }

  if (!account.apiToken) {
    return { ...base, error: "missing apiToken" };
  }

  const started = Date.now();
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(
      () => controller.abort(),
      opts?.timeoutMs ?? 8000,
    );
    let url: URL;
    try {
      url = new URL("/api/v1/me", account.serverUrl);
    } catch {
      return { ...base, error: `invalid serverUrl: ${account.serverUrl}` };
    }
    try {
      const response = await fetch(url.toString(), {
        method: "GET",
        headers: {
          Authorization: `Bearer ${account.apiToken}`,
          Accept: "application/json",
        },
        signal: controller.signal,
      });
      clearTimeout(timeoutId);
      if (!response.ok) {
        return {
          ...base,
          error: `HTTP ${response.status} ${response.statusText}`,
        };
      }
      const elapsed = Date.now() - started;
      return { ...base, ok: true, latencyMs: elapsed };
    } catch (err) {
      clearTimeout(timeoutId);
      return { ...base, error: formatError(err) };
    }
  } catch (err) {
    return { ...base, error: formatError(err) };
  }
}

