        signal: controller.signal,
      });
      clearTimeout(timeoutId);
      if (!response.ok) {
        return {
          ...base,
          error: `HTTP ${response.status} ${response.statusText}`,
        };
      }
      const elapsed = Date.now() - started;
      return { ...base, ok: true, latencyMs: elapsed };
    } catch (err) {
      clearTimeout(timeoutId);
      return { ...base, error: formatError(err) };
    }
  } catch (err) {
    return { ...base, error: formatError(err) };
  }
