import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardMessagingTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

function makePulseBoardMessageId(): string {
  return `pb-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
}

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (
      !(error instanceof Error) ||
      error.message !== "PulseBoard runtime not initialized"
    ) {
      throw error;
    }
  }
}

/**
 * Send a message to a PulseBoard target (board or user) via the REST API.
 *
 * Board targets start with "!" (e.g. "!general").
 * DM targets are plain usernames (e.g. "alice").
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need serverUrl and username in channels.pulseboard).`,
    );
  }
  if (!account.apiToken) {
    throw new Error(
      `PulseBoard account "${account.accountId}" has no apiToken configured.`,
    );
  }

  const target = normalizePulseBoardMessagingTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;

  if (!payload.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  // Determine the REST endpoint: boards use /api/v1/boards/:name/messages,
  // DMs use /api/v1/users/:username/messages.
  let url: URL;
  try {
    const base = new URL(account.serverUrl);
    if (target.startsWith("!")) {
      const boardName = target.slice(1);
      url = new URL(`/api/v1/boards/${encodeURIComponent(boardName)}/messages`, base);
    } else {
      url = new URL(`/api/v1/users/${encodeURIComponent(target)}/messages`, base);
    }
  } catch {
    throw new Error(`Invalid PulseBoard serverUrl: ${account.serverUrl}`);
  }

  const response = await fetch(url.toString(), {
    method: "POST",
    headers: {
      Authorization: `Bearer ${account.apiToken}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ text: payload }),
  });

  if (!response.ok) {
    throw new Error(
      `PulseBoard send failed: HTTP ${response.status} ${response.statusText}`,
    );
  }

  recordPulseBoardOutboundActivity(account.accountId);

  return { messageId: makePulseBoardMessageId(), target };
}

