import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { handlePulseBoardInbound } from "./inbound.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

type StopHandle = { stop: () => void };

/**
 * Connect to the PulseBoard server via WebSocket and process incoming events.
 *
 * The PulseBoard WebSocket protocol delivers JSON frames of the shape:
 *   { type: "message", boardName?: string, senderUsername: string,
 *     text: string, messageId: string, timestamp: number }
 *
 * A `boardName` present indicates a board message; absent indicates a DM.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<StopHandle> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need serverUrl and username in channels.pulseboard).`,
    );
  }
  if (!account.apiToken) {
    throw new Error(
      `PulseBoard account "${account.accountId}" has no apiToken configured.`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let ws: WebSocket | null = null;
  let stopped = false;

  const wsUrl = (() => {
    try {
      const base = new URL(account.serverUrl);
      // Derive WebSocket URL from the HTTP base URL.
      const protocol = base.protocol === "https:" ? "wss:" : "ws:";
      return `${protocol}//${base.host}/api/v1/ws?token=${encodeURIComponent(account.apiToken)}`;
    } catch {
      throw new Error(
        `PulseBoard account "${account.accountId}" has an invalid serverUrl: ${account.serverUrl}`,
      );
    }
  })();

  // Abort-signal support: clean up when the gateway stops the account.
  opts.abortSignal?.addEventListener("abort", () => {
    stopped = true;
    ws?.close(1000, "shutdown");
  });

  ws = new WebSocket(wsUrl);

  ws.addEventListener("open", () => {
    logger.info(
      `[${account.accountId}] connected to PulseBoard at ${account.serverUrl} as ${account.username}`,
    );
  });

  ws.addEventListener("error", (event) => {
    logger.error(
      `[${account.accountId}] PulseBoard WebSocket error: ${String((event as ErrorEvent).message ?? event)}`,
    );
  });

  ws.addEventListener("close", (event) => {
    if (!stopped) {
      logger.warn(
        `[${account.accountId}] PulseBoard WebSocket closed unexpectedly (code=${event.code})`,
      );
    }
  });

  ws.addEventListener("message", async (event) => {
    let frame: Record<string, unknown>;
    try {
      frame = JSON.parse(String(event.data)) as Record<string, unknown>;
    } catch {
      return;
    }

    if (frame.type !== "message") {
      return;
    }

    const senderUsername = String(frame.senderUsername ?? "").trim();
    const text = String(frame.text ?? "").trim();
    if (!senderUsername || !text) {
      return;
    }

    // Ignore messages sent by the bot itself.
    if (senderUsername.toLowerCase() === account.username.toLowerCase()) {
      return;
    }

    const boardName = typeof frame.boardName === "string" ? frame.boardName.trim() : undefined;
    const isBoard = Boolean(boardName);
    const target = isBoard ? boardName! : senderUsername;

    const message: PulseBoardInboundMessage = {
      messageId: String(frame.messageId ?? `pb-${Date.now().toString(36)}`),
      target,
      senderUsername,
      text,
      timestamp: typeof frame.timestamp === "number" ? frame.timestamp : Date.now(),
      isBoard,
    };

    core.channel.activity.record({
      channel: "pulseboard",
      accountId: account.accountId,
      direction: "inbound",
      at: message.timestamp,
    });

    if (opts.onMessage) {
      await opts.onMessage(message);
      return;
    }

    await handlePulseBoardInbound({
      message,
      account,
      config: cfg,
      runtime,
      sendReply: async (replyTarget, replyText) => {
        if (!ws || ws.readyState !== WebSocket.OPEN) {
          return;
        }
        // Use the WebSocket send path for low-latency in-session replies.
        ws.send(
          JSON.stringify({
            type: "send",
            target: replyTarget,
            text: replyText,
          }),
        );
        opts.statusSink?.({ lastOutboundAt: Date.now() });
        core.channel.activity.record({
          channel: "pulseboard",
          accountId: account.accountId,
          direction: "outbound",
        });
      },
      statusSink: opts.statusSink,
    });
  });

  return {
    stop: () => {
      stopped = true;
      ws?.close(1000, "shutdown");
      ws = null;
    },
  };
}

