    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg as CoreConfig).some(
        (accountId) =>
          resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs a server URL, a bot username, and an API token.",
      "Board names start with \"!\" (e.g. !general, !dev).",
      'Set channels.pulseboard.groupPolicy="allowlist" and channels.pulseboard.groups for tighter board access.',
      "Env vars supported: PULSEBOARD_URL, PULSEBOARD_USERNAME, PULSEBOARD_API_TOKEN.",
