        listGroups: async (params) => {
          const entries = await listPulseBoardDirectoryGroupsFromConfig(params);
          return entries.map((entry) => ({ ...entry, name: entry.id }));
        },
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount, PulseBoardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          serverUrl: account.serverUrl,
          username: account.username,
          probe: snapshot.probe,
          lastProbeAt: snapshot.lastProbeAt ?? null,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseBoard(cfg as CoreConfig, {
            accountId: account.accountId,
